from flask import Flask, request, jsonify
import pickle
import os
import uuid

app = Flask(__name__)
UPLOAD_FOLDER = 'uploaded_models'
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

def load_model(file_path):
    with open(file_path, 'rb') as file:
        model = pickle.load(file)
    return model

@app.route('/upload_model', methods=['POST'])
def upload_model():
    if 'model' not in request.files:
        return jsonify({'error': 'No model file provided'}), 400
    model_file = request.files['model']
    if model_file.filename == '':
        return jsonify({'error': 'No model file selected'}), 400
    model_id = str(uuid.uuid4())
    model_path = os.path.join(UPLOAD_FOLDER, model_id)
    model_file.save(model_path)
    return jsonify({'message': 'Model uploaded successfully', 'model_id': model_id}), 200

@app.route('/predict/<model_id>', methods=['POST'])
def predict(model_id):
    model_path = os.path.join(UPLOAD_FOLDER, model_id)
    if not os.path.exists(model_path):
        return jsonify({'error': 'Model not found'}), 404
    model = load_model(model_path)
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No input data provided'}), 400
    try:
        prediction = model.predict(data)
        return jsonify({'prediction': prediction}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)